/**
 * 全集（Collected Works）store
 *
 * 經典學者全集的「最外層」作家 hub 資料：學術貢獻簡介、肖像、生平學術年表、
 * 按類別與年分編排的完整著作目錄（含轉錄狀態）。
 *
 * - portal：/collected-works（列出所有作家）
 * - 作家 hub：/collected-works/[slug]（簡介＋肖像＋年表＋著作目錄）
 * - 單卷閱讀走全集專屬 reader /collected-works/[slug]/[ebookId]；
 *   全集卷在 ebooks.collection='collected-works'，不會出現在 /ebook 圖書館
 *
 * 編輯方式：直接改本檔（沿用 stores/speech.ts、/works 的 repo-committed 模式）。
 * 肖像走 Wikimedia Commons 公有領域圖（Special:FilePath，?width= 取縮圖），不用 Supabase Storage。
 * 方法論與版權盡職調查見 .claude/skills/ebook-collected-works/。
 */
import { defineStore } from 'pinia'

/** 轉錄狀態 */
export type WorkStatus =
  | 'done' // 已轉錄上架，可進 reader
  | 'in-progress' // 轉錄中（pilot / 部分章節）
  | 'planned' // 已排入、尚未轉錄
  | 'copyright' // 受版權限制，待合法來源

export interface CwTimelineEntry {
  year: string // "1823"、"1846–1848"
  text: string // 事件（繁中）
}

/**
 * 文體（決定 reader 版面）。ingest／翻譯時先判定（見 scripts 的 classify_genre）：
 * - dialogue 對話錄（講者分行）／verse 詩歌讚歌（保留詩行詩節）／aphorism 格言命題（逐條編號卡）
 * - quaestio 經院問答（異議→反之→正解→答覆）／treatise 論著／essay 散文／lecture 講義
 * - diary-letters 日記書信／narrative 敘事。未標＝treatise 通用版面。
 * 內容慣例：對話錄／問答段落以 `〔角色〕內文` 起始；詩歌保留單行換行（詩行）與空行（詩節）。
 */
export type CwGenre =
  | 'dialogue' | 'verse' | 'aphorism' | 'quaestio'
  | 'treatise' | 'essay' | 'lecture' | 'diary-letters' | 'narrative'

export interface CwWork {
  title: string // 繁中書名
  titleOriginal?: string // 原文書名（英／德…）
  year: string // 出版年（顯示用，可為區間）
  yearSort: number // 排序用單一年分
  category: string // 類別／群組（hub 內分組依據）
  genre?: CwGenre // 文體（決定 reader 版面；未標＝通用）
  languages?: string[] // 可得來源語言 code，如 ['en','de']
  status: WorkStatus
  ebookId?: string // 已轉錄時連到 /collected-works/[slug]/[ebookId]
  externalUrl?: string // 連到獨立 corpus／portal（如東方聖書），優先於 ebookId
  note?: string // 備註（版權、進度…）
}

export interface CwAuthor {
  slug: string
  name: string // 繁中全名
  nameEn?: string
  nameOriginal?: string
  lifespan: string // "1823–1900"
  disciplineGroup: string // 學科分組（portal 依此分區：哲學／社會學／宗教學／神學／佛學／心理學／人類學…）
  sortYear?: number // 學科組內排序用（生年；BCE 為負）。缺省者維持陣列插入序、排在有值者之後
  era?: string // 年代分層（僅哲學／神學用；如「古代」「中世紀」「近代」「現代與當代」「教父時代」「宗教改革」）
  region?: string // 地域分層（僅哲學／神學用；如「希臘‧地中海」「西方」「伊斯蘭」「中國」「東方（希臘／東正教）」）
  discipline: string // 一句話定位（portal 卡片副標）
  fields: string[] // 領域標籤
  portraitUrl: string
  portraitCredit?: string
  color: string // tailwind 色（safelist 見 tailwind.config.ts）
  emoji: string
  contribution: string[] // 學術貢獻簡介（繁中，段落陣列）
  sourceNote?: string // 來源／語言策略一句話
  timeline: CwTimelineEntry[]
  works: CwWork[]
}

